-- --------------------------------------------------------
-- Table : sculptures
-- --------------------------------------------------------

CREATE TABLE IF NOT EXISTS `sculptures` (
  `id` INT(11) NOT NULL AUTO_INCREMENT,
  `nom_sculpture` VARCHAR(255) NOT NULL,
  `auteur` VARCHAR(255) DEFAULT NULL,
  `date` VARCHAR(100) DEFAULT NULL,
  `musee_actuel` VARCHAR(255) DEFAULT NULL,
  `materiau` VARCHAR(255) DEFAULT NULL,
  `hauteur` VARCHAR(100) DEFAULT NULL,
  `poids` VARCHAR(100) DEFAULT NULL,
  `mouvement_artistique` VARCHAR(255) DEFAULT NULL,
  `particularite` TEXT DEFAULT NULL,
  `descriptif` TEXT DEFAULT NULL,
  `modele_3d_disponible` TINYINT(1) NOT NULL DEFAULT 0,
  `modele_3d_chemin` VARCHAR(255) DEFAULT NULL,
  `image_url` VARCHAR(500) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

